## Overview
Generic connection pool with budget integration, health checks, and structured
lifecycle management for database connections.

## Design

### Pool Configuration
```rust
pub struct PoolConfig {
    /// Minimum connections to maintain.
    pub min_connections: u32,
    /// Maximum connections allowed.
    pub max_connections: u32,
    /// Connection acquire timeout.
    pub acquire_timeout: Duration,
    /// Connection idle timeout before cleanup.
    pub idle_timeout: Duration,
    /// Connection max lifetime.
    pub max_lifetime: Duration,
    /// Health check interval.
    pub health_check_interval: Duration,
    /// Test query for health checks.
    pub test_query: Option<String>,
}
```

### Pool
```rust
pub struct Pool<C: Connection> {
    config: PoolConfig,
    connections: Arc<Mutex<PoolState<C>>>,
    connector: Box<dyn Connector<C>>,
    semaphore: Semaphore,
}

struct PoolState<C> {
    idle: VecDeque<PooledConnection<C>>,
    in_use: usize,
    total: usize,
}

impl<C: Connection> Pool<C> {
    /// Create a new pool.
    pub async fn new(cx: &Cx, config: PoolConfig, connector: impl Connector<C> + 'static) -> Outcome<Self, PoolError> {
        let pool = Self {
            config: config.clone(),
            connections: Arc::new(Mutex::new(PoolState::new())),
            connector: Box::new(connector),
            semaphore: Semaphore::new(config.max_connections as usize),
        };

        // Pre-create minimum connections
        for _ in 0..config.min_connections {
            let conn = pool.connector.connect(cx).await?;
            pool.connections.lock().unwrap().idle.push_back(PooledConnection::new(conn));
        }

        // Start health check task
        cx.spawn(pool.health_check_loop());

        Ok(pool)
    }

    /// Acquire a connection from the pool.
    pub async fn acquire(&self, cx: &Cx) -> Outcome<PooledGuard<'_, C>, PoolError> {
        cx.checkpoint()?;

        // Wait for available slot (respects budget)
        let permit = cx.with_deadline(self.config.acquire_timeout, async {
            self.semaphore.acquire().await
        }).await?;

        // Try to get idle connection
        let conn = {
            let mut state = self.connections.lock().unwrap();
            state.idle.pop_front()
        };

        let conn = match conn {
            Some(c) if !c.is_expired(&self.config) => c,
            _ => {
                // Create new connection
                let c = self.connector.connect(cx).await?;
                PooledConnection::new(c)
            }
        };

        Ok(PooledGuard {
            pool: self,
            conn: Some(conn),
            permit,
        })
    }

    /// Close the pool, waiting for all connections to return.
    pub async fn close(&self, cx: &Cx) -> Outcome<(), PoolError> {
        // Mark pool as closing
        // Wait for all in_use connections to return
        // Close all connections
    }
}
```

### Pooled Guard (RAII)
```rust
pub struct PooledGuard<'a, C: Connection> {
    pool: &'a Pool<C>,
    conn: Option<PooledConnection<C>>,
    permit: SemaphorePermit<'a>,
}

impl<'a, C: Connection> Deref for PooledGuard<'a, C> {
    type Target = C;
    fn deref(&self) -> &C {
        &self.conn.as_ref().unwrap().inner
    }
}

impl<'a, C: Connection> DerefMut for PooledGuard<'a, C> {
    fn deref_mut(&mut self) -> &mut C {
        &mut self.conn.as_mut().unwrap().inner
    }
}

impl<'a, C: Connection> Drop for PooledGuard<'a, C> {
    fn drop(&mut self) {
        if let Some(conn) = self.conn.take() {
            // Return connection to pool
            let mut state = self.pool.connections.lock().unwrap();
            if conn.is_healthy() {
                state.idle.push_back(conn);
            } else {
                // Discard unhealthy connection
                state.total -= 1;
            }
        }
        // permit is automatically released
    }
}
```

### Health Checks
```rust
impl<C: Connection> Pool<C> {
    async fn health_check_loop(&self, cx: &Cx) {
        loop {
            cx.sleep(self.config.health_check_interval).await;
            cx.checkpoint()?;

            // Check idle connections
            let mut to_check = Vec::new();
            {
                let mut state = self.connections.lock().unwrap();
                // Take connections for health check
                while let Some(conn) = state.idle.pop_front() {
                    if conn.is_expired(&self.config) {
                        state.total -= 1;  // Don't check, just discard
                    } else {
                        to_check.push(conn);
                    }
                }
            }

            // Health check each connection
            for mut conn in to_check {
                if let Some(ref query) = self.config.test_query {
                    if conn.inner.ping(cx).await.is_ok() {
                        let mut state = self.connections.lock().unwrap();
                        state.idle.push_back(conn);
                    }
                } else {
                    let mut state = self.connections.lock().unwrap();
                    state.idle.push_back(conn);
                }
            }

            // Maintain minimum connections
            self.maintain_minimum(cx).await;
        }
    }
}
```

### Budget Integration
```rust
impl<C: Connection> Pool<C> {
    /// Acquire with budget constraints.
    pub async fn acquire_with_budget(&self, cx: &Cx) -> Outcome<PooledGuard<'_, C>, PoolError> {
        // Check if we have connection budget remaining
        if cx.budget().connection_budget == 0 {
            return Err(PoolError::BudgetExhausted);
        }

        // Consume one connection from budget
        cx.consume_connection_budget(1);

        self.acquire(cx).await
    }
}
```

